#include <bits/stdc++.h>
using namespace std;
string S1[101] ={},S2[101]={};
int main(){
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>S1[i]>>S2[i];
	}
	for(int i=0;i<n;i++){
				if(S1[i]==S2[i])
				{
					cout<<"Tie"<<endl;
				}
		else{if(S1[i]>S2[i])
		{if(S1[i]=="Scissors" && S2[i]=="Paper" ){
			cout<<"Player1"<<endl;
		}	else{
			cout<<"Player2"<<endl;
		}}
		if(S1[i]<S2[i])
		{	if(S2[i]=="Scissors" && S1[i]=="Paper" ){
			cout<<"Player2"<<endl;
		}	else{
			cout<<"Player1"<<endl;
		}}
	}
	}
	return 0;
}
